export function nextGeneration(liveCells: Cell[]): Cell[] {
  const aliveCells = new Set(liveCells.map(cellKey));
  const isAlive = (cell: Cell): boolean => aliveCells.has(cellKey(cell));
  const countLiveNeighbors = ([x, y]: Cell): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isAlive([x + dx, y + dy])).length;
  const survives = (cell: Cell): boolean => {
    const neighbors = countLiveNeighbors(cell);
    return neighbors === 2 || neighbors === 3;
  };

  const candidateDeadCells = new Map<string, Cell>();
  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      if (!isAlive(neighbor)) candidateDeadCells.set(cellKey(neighbor), neighbor);
    }
  }
  const births: Cell[] = [];
  for (const cell of candidateDeadCells.values()) {
    if (countLiveNeighbors(cell) === 3) births.push(cell);
  }

  return [...liveCells.filter(survives), ...births];
}

