const neighborsOf = ([x, y]: Cell): Cell[] =>
  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const aliveKeys = new Set(liveCells.map(cellKey));
  const isAlive = (cell: Cell): boolean => aliveKeys.has(cellKey(cell));
  const liveNeighborCount = (cell: Cell): number =>
    neighborsOf(cell).filter(isAlive).length;

  const survivors = liveCells.filter((cell) => {
    const n = liveNeighborCount(cell);
    return n === 2 || n === 3;
  });

  const birthCandidates = new Map<string, Cell>();
  for (const cell of liveCells.flatMap(neighborsOf)) {
    if (!isAlive(cell)) birthCandidates.set(cellKey(cell), cell);
  }
  const births = [...birthCandidates.values()].filter(
    (cell) => liveNeighborCount(cell) === 3,
  );

  return [...survivors, ...births];
}
